UPDATE program
SET time = #{time}
WHERE program_num = (SELECT program_num FROM schedule WHERE schedule_code = #{schedule_code})

mapper.delete:
DELETE e
FROM enroll e
JOIN (
    SELECT s_id FROM enroll WHERE enrol_id = #{enroll_id}
) temp ON e.s_id = temp.s_id
JOIN user u ON e.login_id = u.login_id
WHERE u.member_no = #{member_no};

mapper.update:
UPDATE enroll
SET login_id = (SELECT login_id FROM user WHERE member_no = #{member_no})
WHERE enrol_id = #{enroll_id}

UPDATE user
SET member_hp = #{member_hp}, member_type = #{member_type}, team_name = #{team_name}
WHERE member_no = #{member_no}

UPDATE popup
SET status = #{file_status}
WHERE popup_id = #{type}
